import com.xuenn.bet188.quickmenu.MenuPreferencesManager
import com.xuenn.bet188.revamp.callback.IFacebookOAuthListener
import com.xuenn.bet188.revamp.model.data.Constants
import com.xuenn.bet188.revamp.model.data.Constants.KEY_BUNDLE_MFA_DATA
import com.xuenn.bet188.revamp.model.data.Constants.RESULT_DATA_MEMBER_INFO
import com.xuenn.bet188.revamp.model.data.MFAChallengeObject
import com.xuenn.bet188.revamp.model.data.OAuthUserData
import com.xuenn.bet188.revamp.model.data.UiStr
import com.xuenn.bet188.revamp.utils.CommonUtils
import com.xuenn.bet188.revamp.model.data.repo.StringsRepository.getString
import com.xuenn.bet188.revamp.utils.disableCopyPaste
import com.xuenn.bet188.revamp.utils.hideKeyboard
import com.xuenn.bet188.revamp.utils.oauth.FacebookOAuthHelper
import com.xuenn.bet188.revamp.utils.oauth.FacebookOAuthUtil
import com.xuenn.bet188.revamp.view.MFAVerifyActivity
import com.xuenn.bet188.revamp.view.base.BaseActivityOptions
import com.xuenn.bet188.revamp.view.base.BaseBindingHeaderActivity
import com.xuenn.bet188.revamp.view.lockpattern.LockPatternActivity
import com.xuenn.bet188.revamp.viewmodel.LOCK_PATTERN_FUNCTION_KEY
import com.xuenn.bet188.revamp.viewmodel.LobbyViewModel
import com.xuenn.bet188.revamp.viewmodel.LockPatternFunction
import com.xuenn.bet188.revamp.viewmodel.LoginViewModel
import com.xuenn.bet188.revamp.viewmodel.LoginViewModel.LoginResult
import com.xuenn.bet188.revamp.viewmodel.RESULT_DATA_SAVE_KEY
import com.xuenn.bet188.revamp.widget.BottomNavigationView
import com.xuenn.bet188.revamp.widget.IconNotifyDialogFragment
import org.koin.androidx.viewmodel.ext.android.viewModel
import org.koin.core.parameter.parametersOf
import java.util.Calendar


class LoginActivity : BaseBindingHeaderActivity<ActivityLoginBinding>(), MenuPreferencesManager.OnPreferenceChangedListener {

    private val mViewModel: LoginViewModel by viewModel()
    private val mLobbyViewModel: LobbyViewModel by viewModel { parametersOf(this) }

    var usernameBeEdited: Boolean = false
    var pwdBeEdited: Boolean = false

    private var isNewTrustDevice = false

    override fun getActivityID(): Int {
        return ConstantsBet188.BOTTOM_NAVIGATION_ICON_DEFAULT
    }

    override fun getLayHeaderBinding(): ViewPageHeaderBinding? {
        return binding.layHeader.headerBinding
    }

    override fun getBottomNavigationView(): BottomNavigationView? {
        return null
    }

    override fun getContentView(): Int {
        return R.layout.activity_login
    }

    override fun onCreateViewBuilder(): BaseActivityOptions.Builder? {
        return super.onCreateViewBuilder()
            ?.setLogoVisible(true)
            ?.setLogoIcon(StyleManager.logoIcon)
            ?.setMenuVisible(true)
            ?.setBottomNavigationBarVisible(false)
    }

    override fun initData() {
        super.initData()

        mViewModel.init(this)
        mViewModel.progressDialogObservable.observe(this) { isShow ->
            if (isShow) showLoadingDialog() else dismissLoadingDialog()
        }

        mViewModel.isSponsorUpdated.observe(this) { isUpdatedSuccess ->
            binding.footerView.reloadFooter(isUpdatedSuccess)
        }

        mViewModel.loginReturnStatus.observe(this) { status ->
            when (status) {
                is LoginResult.Success -> mLobbyViewModel.fetchRegionTheme(this)

                is LoginResult.OAuthFail -> {
                    val notifyData = IconNotifyDialogFragment.IconNotifyObject(
                        R.mipmap.ic_fail_active,
                        getString(UiStr.TXTAUTHENTICATIONFAILED),
                        getString(UiStr.MSGSIGNWITHDIFFERENTACCOUNT),
                        getString(UiStr.TXTBTNCOMOK)
                    )

                    IconNotifyDialogFragment.Companion.newInstance(notifyData)
                        .setListener(this)
                        .show(supportFragmentManager, IconNotifyDialogFragment::class.java.simpleName)
                }
                is LoginResult.VerifyDevice -> {
                    openVerifyDevicePage(status.mfaData)
                }
                else -> {

                }
            }

        }

        mLobbyViewModel.isThemeDone.observe(this) { isThemeDone ->
            if (isThemeDone) {
                mViewModel.setEnableBioAuth(false)
                openUpLockPatternSetting()
            }
        }

        binding.vm = mViewModel
    }

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        if (intent.extras != null) {
            binding.username.setText(intent.extras!!.getString(Constants.BUNDLE_ACCOUNT, ""))
        }
        MenuPreferencesManager.getInstance().addPreferenceChangedListener(this)
        // PIM-34486
        // Clear the cookie to make sure member won't use the session from latest member.
        CookieManager.getInstance().removeAllCookies(null)
        CookieManager.getInstance().flush()
    }


    override fun onDestroy() {
        super.onDestroy()
        MenuPreferencesManager.getInstance().removeInvalidateListener(this)
    }


    override fun onNewIntent(intent: Intent?) {
        super.onNewIntent(intent)
        setIntent(intent)
    }

    override fun initView() {
        super.initView()

        // Disable copy paste for EditText
        binding.username.disableCopyPaste()
        binding.pwd.disableCopyPaste()

        binding.username.addTextChangedListener(object : TextWatcher {
            override fun beforeTextChanged(s: CharSequence, start: Int, count: Int, after: Int) {
                binding.usernameLayout.error = ""
            }

            override fun onTextChanged(s: CharSequence, start: Int, before: Int, count: Int) {}
            override fun afterTextChanged(editable: Editable) {
                usernameBeEdited = true
                checkIsEnableLoginBtn()
            }
        })
        binding.username.setOnFocusChangeListener { _, hasFocus ->
            if (!hasFocus && usernameBeEdited) {
                if ((binding.username.text!!.isEmpty()))
                    binding.usernameLayout.error = getString(UiStr.HELPJOINUSREQUIRED)
            }
        }


        binding.pwd.addTextChangedListener(object : TextWatcher {
            override fun beforeTextChanged(s: CharSequence, start: Int, count: Int, after: Int) {
                binding.pwdLayout.error = ""
            }

            override fun onTextChanged(s: CharSequence, start: Int, before: Int, count: Int) {}
            override fun afterTextChanged(editable: Editable) {
                pwdBeEdited = true
                checkIsEnableLoginBtn()
            }
        })
        binding.pwd.setOnFocusChangeListener { _, hasFocus ->
            if (!hasFocus && pwdBeEdited) {
                if ((binding.pwd.text!!.isEmpty()))
                    binding.pwdLayout.error = getString(UiStr.HELPJOINUSREQUIRED)
            }
        }


        //btn
        binding.btnLogin.setOnClickListener {
            hideKeyboard(binding.btnLogin)

            mViewModel.performLogin(binding.username.text.toString(), binding.pwd.text.toString())
        }

        binding.googleLayout.btnGoogle.setOnClickListener {
            hideKeyboard(binding.googleLayout.btnGoogle)

            mViewModel.showSelectGoogleAccount(this@LoginActivity)
        }

        binding.facebookLayout.btnFacebook.setOnClickListener {
            hideKeyboard(binding.facebookLayout.btnFacebook)

            FacebookOAuthHelper.launchSignIn(
                this@LoginActivity,
                Calendar.getInstance().timeInMillis,
                object : IFacebookOAuthListener {
                    override fun facebookOAuthInfo(userInfo: FacebookOAuthUtil.FacebookUserInfo) {
                        mViewModel.performOAuthLogin(
                            OAuthUserData(
                                oAuthType = Constants.OAuthType.Facebook,
                                oAuthEmail = userInfo.email,
                                oAuthId = userInfo.oAuthIdForSPI,
                                oAuthName = userInfo.name,
                                oAuthCustomData1 = userInfo.facebookAppId
                            )
                        )
                    }

                    override fun setProgressStatus(isInProgress: Boolean) {
                        mViewModel.progressDialogObservable.value = isInProgress
                    }

                    override fun launchFail(e: Exception) {
                        mViewModel.launchFail(e)

                        if (e !is FacebookOAuthUtil.FacebookCancelException) {
                            DialogUtil.showSimpleDialog(
                                this@LoginActivity,
                                getString(UiStr.TXTLOGINFAIL),
                                e.message,
                                getString(UiStr.TXTBTNCOMOK),
                                0
                            )
                        }
                    }

                    override fun reachOAuthLimit(context: Context) {
                        mViewModel.reachOAuthLimit(context)
                    }
                })
        }

        binding.footerView.setDataView(FooterParameter(this))
    }

    override fun onResume() {
        super.onResume()

        binding.footerView.reloadFooter(false)  //hide sponsor first
        mViewModel.performGetSponsorList()
        mViewModel.initOAuthRecord(this)
    }

    fun checkIsEnableLoginBtn() {
        binding.btnLogin.isEnabled = !TextUtils.isEmpty(binding.username.text) && binding.username.text.toString().length >= 5
                && !TextUtils.isEmpty(binding.pwd.text) && binding.pwd.text.toString().length >= 5
    }

    private fun openUpLockPatternSetting() {
        val intent = Intent(this@LoginActivity, LockPatternActivity::class.java).apply {
            putExtras(
                bundleOf(
                    LOCK_PATTERN_FUNCTION_KEY to LockPatternFunction.SET_KEY,
                )
            )
        }
        lockPatternActivityLaunchForResult.launch(intent)
    }

    private var lockPatternActivityLaunchForResult = registerForActivityResult(
        ActivityResultContracts.StartActivityForResult()
    ) { result ->
        val resultDataIntent: Intent? = result.data
        if (result.resultCode == RESULT_OK) {
            val lockPattenKey = resultDataIntent?.getStringExtra(RESULT_DATA_SAVE_KEY)
                ?: ""
            mViewModel.saveLockPattern(lockPattenKey)
            mViewModel.openSuccessPage(isNewTrustDevice)
        } else {
            CommonUtils.handleUserLogout(this, true)
        }
    }

    private fun openVerifyDevicePage(mfaData: MFAChallengeObject) {
        val intent = Intent(this@LoginActivity, MFAVerifyActivity::class.java).apply {
            putExtra(KEY_BUNDLE_MFA_DATA, mfaData)
        }
        verifyDeviceActivityLaunchForResult.launch(intent)
    }

    private var verifyDeviceActivityLaunchForResult = registerForActivityResult(
        ActivityResultContracts.StartActivityForResult()
    ) { result ->
        if (result.resultCode == RESULT_OK) {
            isNewTrustDevice = true
            mViewModel.onTrustDeviceSuccess(this)
        }
    }

    override fun onBackPressed() {
        finish()
    }

    override fun finish() {
        hideKeyboard(binding.root)
        super.finish()
    }

    companion object {
        fun launch(activity: Activity) {
            val intent = Intent(activity, LoginActivity::class.java)
            activity.startActivity(intent)
            activity.overridePendingTransition(R.anim.slide_in_from_right, R.anim.slide_out_from_left)
        }

        fun launchClearTop(activity: Activity) {
            val intent = Intent(activity, LoginActivity::class.java)
            intent.addFlags(Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TASK)
            activity.startActivity(intent)
            activity.overridePendingTransition(R.anim.slide_in_from_right, R.anim.slide_out_from_left)
        }
    }

    override fun getFragmentContainer(): Int = -1

    override fun onPreferenceChanged(type: MenuPreferencesManager.PreferenceChangedType?) {
        when (type) {
            MenuPreferencesManager.PreferenceChangedType.REGION,
            MenuPreferencesManager.PreferenceChangedType.LANGUAGE -> {
                recreateActivity()
            }

            else -> {}
        }
    }

    private fun recreateActivity() {
        Intent(this, LoginActivity::class.java).apply {
            if (binding.username.text!!.isNotEmpty()) {
                val bundle = Bundle()
                bundle.putString(Constants.BUNDLE_ACCOUNT, binding.username.text.toString())
                putExtras(bundle)
            }
            addFlags(Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TASK)
            startActivity(this)
        }
    }
}

